questions.question:
What will be the output of the following code? Explain the behavior of static variable.

void counter() {
    static int count = 0;
    count++;
    printf("%d ", count);
}
int main() {
    counter();
    counter();
    counter();
    return 0;
}

What will be the output of the following code? Trace the execution and explain the behavior of all variables.

#include <stdio.h>
int x = 10;  // Global variable
void func() {
    static int s = 5;
    int a = 0;
    a++;
    s++;
    x++;
    printf("a=%d, s=%d, x=%d\n", a, s, x);
}
int main() {
    func();
    func();
    func();
    return 0;
}
